"""Vector database operations: ChromaDB local + production patterns."""
import os
import math
from typing import Any


# ── Pure-Python cosine similarity (no numpy) ─────────────────────
def cosine_sim(a: list[float], b: list[float]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    mag_a = math.sqrt(sum(x**2 for x in a))
    mag_b = math.sqrt(sum(x**2 for x in b))
    return dot / (mag_a * mag_b) if mag_a and mag_b else 0.0


# ── ChromaDB wrapper ─────────────────────────────────────────────
class ChromaDocStore:
    def __init__(self, collection_name: str, persist_path: str = "./chroma_db"):
        import chromadb
        self.client = chromadb.PersistentClient(path=persist_path)
        self.collection = self.client.get_or_create_collection(
            name=collection_name,
            metadata={"hnsw:space": "cosine"}
        )

    def add_documents(
        self,
        texts: list[str],
        metadatas: list[dict] | None = None,
        ids: list[str] | None = None,
    ) -> None:
        ids = ids or [f"doc_{i}" for i in range(len(texts))]
        metadatas = metadatas or [{} for _ in texts]
        self.collection.add(documents=texts, metadatas=metadatas, ids=ids)
        print(f"Added {len(texts)} documents. Total: {self.collection.count()}")

    def search(
        self,
        query: str,
        n_results: int = 5,
        filters: dict | None = None,
    ) -> list[dict]:
        kwargs: dict[str, Any] = {"query_texts": [query], "n_results": n_results}
        if filters:
            kwargs["where"] = filters
        results = self.collection.query(**kwargs)
        output = []
        for i, (doc, meta, dist) in enumerate(zip(
            results["documents"][0],
            results["metadatas"][0],
            results["distances"][0],
        )):
            output.append({
                "rank": i + 1,
                "text": doc,
                "score": 1 - dist,  # chroma returns distance, convert to similarity
                "metadata": meta,
            })
        return output

    def delete(self, ids: list[str]) -> None:
        self.collection.delete(ids=ids)

    def count(self) -> int:
        return self.collection.count()


# ── Embedding + indexing pipeline ────────────────────────────────
class DocumentIndexer:
    def __init__(self, store: ChromaDocStore):
        self.store = store

    def index_documents(self, documents: list[dict]) -> None:
        """Each doc: {text, source, category, year}."""
        texts     = [d["text"] for d in documents]
        metadatas = [{k: v for k, v in d.items() if k != "text"} for d in documents]
        ids       = [f"{d.get('source', 'doc')}_{i}" for i, d in enumerate(documents)]
        self.store.add_documents(texts, metadatas, ids)

    def filtered_search(self, query: str, category: str, top_k: int = 3) -> list[dict]:
        return self.store.search(query, n_results=top_k, filters={"category": category})


# ── Naive linear-scan baseline (for comparison) ──────────────────
class NaiveVectorStore:
    """O(n) brute force — shows why you need a vector DB at scale."""
    def __init__(self):
        self._docs: list[tuple[str, list[float], dict]] = []

    def add(self, text: str, embedding: list[float], metadata: dict) -> None:
        self._docs.append((text, embedding, metadata))

    def search(self, query_embedding: list[float], top_k: int = 5) -> list[dict]:
        scored = [(text, cosine_sim(query_embedding, emb), meta) for text, emb, meta in self._docs]
        scored.sort(key=lambda x: -x[1])
        return [{"text": t, "score": s, "metadata": m} for t, s, m in scored[:top_k]]


if __name__ == "__main__":
    # Demo ChromaDB
    store = ChromaDocStore("ai_docs")
    indexer = DocumentIndexer(store)

    docs = [
        {"text": "BERT introduced bidirectional transformers for NLP",   "source": "arxiv", "category": "nlp",  "year": 2018},
        {"text": "GPT-3 demonstrated few-shot learning at massive scale", "source": "openai","category": "llm",  "year": 2020},
        {"text": "RAG combines retrieval with generation for accuracy",   "source": "meta",  "category": "rag",  "year": 2020},
        {"text": "Attention is all you need — the transformer paper",    "source": "google","category": "nlp",  "year": 2017},
        {"text": "Vector databases enable fast similarity search at scale","source": "blog", "category": "infra","year": 2023},
    ]
    indexer.index_documents(docs)

    print("\n=== Semantic Search ===")
    results = store.search("language models and transformers", n_results=3)
    for r in results:
        print(f"  [{r['score']:.3f}] {r['text'][:60]}")

    print("\n=== Filtered Search (category=nlp) ===")
    filtered = indexer.filtered_search("attention mechanisms", category="nlp")
    for r in filtered:
        print(f"  [{r['score']:.3f}] {r['text'][:60]}")

