class SemanticSearchEngine:
    def __init__(self):
        import chromadb
        client = chromadb.PersistentClient('./product_db')
        self.col = client.get_or_create_collection('products', metadata={'hnsw:space': 'cosine'})

    def index(self, products: list[dict]) -> None:
        texts = [p['description'] for p in products]
        metas = [{k: v for k, v in p.items() if k != 'description'} for p in products]
        ids = [f'prod_{i}' for i in range(len(products))]
        self.col.add(documents=texts, metadatas=metas, ids=ids)

    def search(self, query: str, category=None, max_price=None, in_stock_only=False, top_k=3):
        conditions = []
        if category:
            conditions.append({'category': {'$eq': category}})
        if max_price is not None:
            conditions.append({'price': {'$lte': max_price}})
        if in_stock_only:
            conditions.append({'in_stock': {'$eq': True}})
        where = {'$and': conditions} if len(conditions) > 1 else (conditions[0] if conditions else None)
        kwargs = {'query_texts': [query], 'n_results': top_k}
        if where:
            kwargs['where'] = where
        res = self.col.query(**kwargs)
        return [{'text': doc, 'score': 1 - dist, 'metadata': meta}
                for doc, dist, meta in zip(res['documents'][0], res['distances'][0], res['metadatas'][0])]
